const input = $input.first().json;
const body = input.body || input;

// 🔍 Validation & Sanitization (SEC04)
const payload = {
  booking_id: parseInt(body.booking_id) || null,
  provider_id: parseInt(body.provider_id) || null,
  service_id: parseInt(body.service_id) || null,
  failure_reason: String(body.failure_reason || 'UNKNOWN').substring(0, 100),
  error_message: String(body.error_message || 'No message provided').substring(0, 500),
  error_stack: body.error_stack ? String(body.error_stack).substring(0, 2000) : null,
  original_payload: body.original_payload || {},
  idempotency_key: body.idempotency_key || `gen_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
};

// 📦 Base64 Encoding to bypass comma-splitting bug (GHC-2548)
const b64Payload = Buffer.from(JSON.stringify(payload)).toString('base64');

return [{ json: { b64_payload: b64Payload, ...payload } }];

const result = $input.first().json;
const validated = $('Validate & Encode').first().json;

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      dlq_id: result.out_dlq_id,
      idempotency_key: validated.idempotency_key
    },
    _meta: {
      source: 'DLQ_01_Add_Entry',
      timestamp: new Date().toISOString(),
      workflow_id: $workflow.id
    }
  }
}];
